VALUES
  ('social-worker-moex-05520', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究人員在選舉期間，每個月訪問同一組樣本選民，詢問他們要投票給誰，了解選民投票意向的持續性 與改變的型態。請問研究人員運用下列何者方法？', '["固定樣本覆訪研究（panel study）", "世代研究（cohort study）", "趨勢研究（trend study）", "橫斷研究（cross-sectional study）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05521', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '社會研究具有多重目的，較常見的包括探索、描述及解釋三者。下列關於探索性研究的敘述，何者錯誤？', '["運用人口普查以精準地反映人口特質", "用來檢驗進行較大規模研究的可行性", "做為發展後續研究可以使用的方法", "滿足研究者的好奇心以及更進一步了解事情的渴望"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05522', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於質化田野研究的敘述，下列何者錯誤？', '["適合於自然情境中了解的行為與態度之研究", "適合研究跨時間的社會過程", "強調對現象發生脈絡的理解", "研究發現比較表面，但比較通則化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05523', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '田野研究者在研究裡實際進入研究情境中所建構的一個角色或角色組（set of roles），並參與被觀察對象 的所有日常生活，則他的角色屬於下列何種？', '["完全觀察者", "完全參與者", "參與者身分的觀察者", "觀察者身分的參與者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05524', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '研究人員想探究一個社區組織長久以來招募人員的型態，一開始先訪問最近加入的成員，問他們由誰介 紹加入這個組織，再來訪問被提及的介紹人，再問這些人由誰介紹他們加入，然後再訪問那些被指名的 人。請問此運用方法是下列何者？', '["配額抽樣（quota sampling）", "立意或判斷抽樣（purposive or judgmental sampling）", "機率抽樣（probability sampling）", "滾雪球抽樣（snowball sampling）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05525', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '關於李克特量表（Likert scale）的敘述，下列何者錯誤？', '["是由李克特（Rensis Likert）發展出來測量態度的工具", "受訪者一般會被要求針對一系列的陳述表達同意或不同意的程度", "李克特量表的原始規劃是每一陳述的權重都完全相同", "通常都為複合指標的形式來測量受訪者對一議題態度的強度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05526', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關橫斷研究（cross-sectional study）與縱貫研究（longitudinal study）的敘述，何者錯誤？', '["橫斷研究的研究者通常只選擇一個時段觀察或調查其研究對象", "橫斷研究的研究結果通常無法做因果推論", "「世代研究（cohort study）」是縱貫研究的類型之一，每次都針對同一組對象進行研究", "「固定樣本覆訪研究（panel study）」比「世代研究」更能追蹤研究對象的改變"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05527', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關方案評估或評估研究的敘述，何者錯誤？', '["評估研究的重點在嚴格的檢視介入方案的適當性、有效性與效率等方案的品質", "方案評估影響資金贊助的決策具有高度的政治性，因此應避免利害關係人參與評估的過程", "需求評估屬於方案規劃的評估", "評估方案的效率可分別從成本效用分析及成本效益分析來達成"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05528', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關單案研究設計的敘述，何者錯誤？', '["單案研究設計研究對象只有一個，其對象可能是個人、家庭、機構、團體、社區或方案", "單案研究設計利用重複測量以求穩定的趨勢可供觀察，對可能的外在因素造成的干擾影響有較好的控制", "單案研究設計沒有控制組，在介入前的基線期可視為控制期，介入後的干預期可視為實驗期", "ABAB設計在第二基線期，抽離原有的介入，一段時間後再介入干預，並沒有研究倫理的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-05529', 'social-worker', 'social-worker-moex-106-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '一個好的研究必須有一定的信賴度（dependability）與一致性（consistency），也就是所謂的信度，下列 何者不是常見的信度類型？', '["再測（test-retest）信度", "分數（score）信度", "預測（predictive）信度", "折半（split-half）信度"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:30+00:00", "source_pdf_sha1": "8a86e172f0f5", "answer_pdf_sha1": "58115afe2e3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "106110", "c": "107", "s": "0606", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作研究方法", "year": "106", "exam_name": "106年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、106年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
